  ('elementary-6f0ba476-moex-00570', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-4bd2866a', 'sub-elementary-6f0ba476-04', NULL, 'single_choice', '下列何項政策屬於我國政府的實物補助政策？', '["提供學童免費營養午餐", "發放天然災害慰問金", "低收入戶生活扶助", "發放敬老津貼"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:41+00:00", "source_pdf_sha1": "326081339d0f", "answer_pdf_sha1": "3849b573f8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "財政學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00571', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-4bd2866a', 'sub-elementary-6f0ba476-04', NULL, 'single_choice', '就社會保險而言，下列關於道德危機與逆選擇的敘述，何者錯誤？', '["逆選擇會導致保險制度高估保險費率", "道德危機會增加保險給付", "嚴格審核理賠申請，有助於降低道德危機", "透過強制納保，有助於降低逆選擇情況"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:41+00:00", "source_pdf_sha1": "326081339d0f", "answer_pdf_sha1": "3849b573f8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "財政學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
